async function main() {
  try {
    // World Bank API for GDP (current US$) - China and Japan
    const url = "https://api.worldbank.org/v2/country/CN;JP/indicator/NY.GDP.MKTP.CD?format=json&per_page=5&date=2020:2024";
    const res = await fetch(url);
    const data = JSON.parse(res);

    // Parse the data
    const entries = data[1] || [];
    const chinaData = entries.filter(e => e.countryiso3code === 'CHN');
    const japanData = entries.filter(e => e.countryiso3code === 'JPN');

    console.log("=== China GDP (current US$) ===");
    chinaData.sort((a, b) => b.date - a.date);
    chinaData.forEach(e => console.log(`${e.date}: $${(e.value / 1e12).toFixed(2)} trillion`));

    console.log("\n=== Japan GDP (current US$) ===");
    japanData.sort((a, b) => b.date - a.date);
    japanData.forEach(e => console.log(`${e.date}: $${(e.value / 1e12).toFixed(2)} trillion`));

  } catch(e) {
    console.error("Error:", e.message);
  }
}
main();
